import React, { useState, useEffect, useRef } from "react";
import Footer from "components/Footers/Footer.js";
import Navbar from "components/Navbars/AuthNavbar.js";

// ==================== مكون قائمة الطلبات ====================
const OrderList = ({ orders, onUpdateOrderStatus }) => {
  const [selectedOrder, setSelectedOrder] = useState(null);
  const [selectedGroup, setSelectedGroup] = useState(null);
  const containerRef = useRef(null);
  const [showScrollButton, setShowScrollButton] = useState(false);

  // تجميع الطلبات المتطابقة (نفس المنتج)
  const groupOrders = () => {
    const groups = {};
    orders.forEach(order => {
      const key = `${order.name}_${order.price}`;
      if (!groups[key]) {
        groups[key] = {
          id: key,
          name: order.name,
          price: order.price,
          quantity: 0,
          orders: [],
          status: order.status
        };
      }
      groups[key].quantity++;
      groups[key].orders.push(order);
      // إذا كان أي طلب في المجموعة ملغي أو مكتمل، نحدد الحالة العامة
      if (order.status === 'cancelled') groups[key].status = 'cancelled';
      else if (order.status === 'completed') groups[key].status = 'completed';
      else groups[key].status = 'pending';
    });
    return Object.values(groups);
  };

  const orderGroups = groupOrders();

  // التمرير التلقائي للأسفل عند إضافة طلب جديد
  useEffect(() => {
    if (containerRef.current) {
      containerRef.current.scrollTop = containerRef.current.scrollHeight;
    }
  }, [orders]);

  // إظهار زر التمرير عند overflow
  const handleScroll = () => {
    if (containerRef.current) {
      const { scrollTop, scrollHeight, clientHeight } = containerRef.current;
      setShowScrollButton(scrollHeight - scrollTop > clientHeight + 50);
    }
  };

  const scrollToTop = () => {
    if (containerRef.current) {
      containerRef.current.scrollTo({ top: 0, behavior: 'smooth' });
    }
  };

  // عرض تفاصيل طلبية فردية
  const OrderDetailModal = ({ order, onClose }) => (
    <div className="modal-overlay" onClick={onClose}>
      <div className="modal-content-order" onClick={(e) => e.stopPropagation()}>
        <button onClick={onClose} className="close-btn">✕</button>
        <div className="text-center">
          <div className="text-5xl mb-3">🍽️</div>
          <h3 className="text-xl font-bold text-white mb-2">{order.name}</h3>
          <div className="order-detail-info">
            <p><span className="detail-label">💰 السعر:</span> {order.price} دج</p>
            <p><span className="detail-label">📦 الكمية:</span> 1</p>
            <p><span className="detail-label">💵 الإجمالي:</span> {order.price} دج</p>
            <p><span className="detail-label">🕐 الوقت:</span> {order.time || 'الآن'}</p>
            <p><span className="detail-label">📝 ملاحظات:</span> {order.notes || 'لا توجد'}</p>
          </div>
          <div className="order-detail-buttons">
            <button 
              onClick={() => { onUpdateOrderStatus(order.id, 'completed'); onClose(); }}
              className="btn-livre"
            >
              ✅ Livrée
            </button>
            <button 
              onClick={() => { onUpdateOrderStatus(order.id, 'cancelled'); onClose(); }}
              className="btn-annule"
            >
              ❌ Annulée
            </button>
          </div>
        </div>
      </div>
    </div>
  );

  // عرض تفاصيل مجموعة طلبات (نفس الشيء)
  const GroupDetailModal = ({ group, onClose }) => (
    <div className="modal-overlay" onClick={onClose}>
      <div className="modal-content-order" onClick={(e) => e.stopPropagation()}>
        <button onClick={onClose} className="close-btn">✕</button>
        <div className="text-center">
          <div className="text-5xl mb-3">📦</div>
          <h3 className="text-xl font-bold text-white mb-2">{group.name}</h3>
          <div className="order-detail-info">
            <p><span className="detail-label">💰 السعر للواحدة:</span> {group.price} دج</p>
            <p><span className="detail-label">🔢 العدد الإجمالي:</span> {group.quantity}</p>
            <p><span className="detail-label">💵 السعر الإجمالي:</span> {group.price * group.quantity} دج</p>
            <p><span className="detail-label">📋 الحالة:</span> 
              <span className={`status-badge-detail ${group.status}`}>
                {group.status === 'pending' ? 'في الانتظار' : group.status === 'completed' ? 'تم التوصيل' : 'ملغي'}
              </span>
            </p>
          </div>
          <div className="order-detail-buttons">
            <button 
              onClick={() => { 
                group.orders.forEach(order => onUpdateOrderStatus(order.id, 'completed')); 
                onClose(); 
              }}
              className="btn-livre"
            >
              ✅ Livrée (الكل)
            </button>
            <button 
              onClick={() => { 
                group.orders.forEach(order => onUpdateOrderStatus(order.id, 'cancelled')); 
                onClose(); 
              }}
              className="btn-annule"
            >
              ❌ Annulée (الكل)
            </button>
          </div>
          <div className="mt-3 text-sm text-gray-400">
            <p>📌 {group.quantity} طلبية من نفس المنتج</p>
          </div>
        </div>
      </div>
    </div>
  );

  return (
    <div className="order-list-container">
      <div className="order-list-header">
        <h3 className="order-list-title">
          📋 قائمة الطلبات
          <span className="order-count-badge">{orders.length}</span>
        </h3>
        <div className="header-actions">
          <button className="refresh-btn" onClick={() => window.location.reload()}>
            🔄
          </button>
        </div>
      </div>
      
      <div 
        ref={containerRef}
        className="order-list-scroll"
        onScroll={handleScroll}
      >
        {orderGroups.length === 0 ? (
          <div className="empty-orders">
            <div className="empty-icon">🍽️</div>
            <p>لا توجد طلبات حالياً</p>
            <p className="empty-sub">ستظهر الطلبات هنا تلقائياً</p>
          </div>
        ) : (
          orderGroups.map((group, idx) => (
            <div 
              key={group.id}
              className={`order-item ${group.status} animate-slide-up`}
              style={{ animationDelay: `${idx * 0.05}s` }}
              onClick={() => {
                if (group.quantity === 1) {
                  setSelectedOrder(group.orders[0]);
                } else {
                  setSelectedGroup(group);
                }
              }}
            >
              <div className="order-item-content">
                <div className="order-info">
                  <span className="order-icon">
                    {group.name.includes('قهوة') ? '☕' : 
                     group.name.includes('شاي') ? '🍵' :
                     group.name.includes('بيتزا') ? '🍕' :
                     group.name.includes('برغر') ? '🍔' : '🍽️'}
                  </span>
                  <div className="order-details">
                    <div className="order-name">{group.name}</div>
                    <div className="order-meta">
                      <span className="order-price">{group.price} دج</span>
                      {group.quantity > 1 && (
                        <span className="order-quantity-badge">×{group.quantity}</span>
                      )}
                    </div>
                  </div>
                </div>
                <div className="order-actions">
                  {group.quantity > 1 && (
                    <span className="group-badge">
                      {group.quantity} عناصر
                    </span>
                  )}
                  <div className={`order-status ${group.status}`}>
                    {group.status === 'pending' ? '⏳' : group.status === 'completed' ? '✅' : '❌'}
                  </div>
                </div>
              </div>
            </div>
          ))
        )}
      </div>
      
      {showScrollButton && (
        <button className="scroll-to-top" onClick={scrollToTop}>
          ↑
        </button>
      )}
      
      {/* المودالات */}
      {selectedOrder && (
        <OrderDetailModal 
          order={selectedOrder} 
          onClose={() => setSelectedOrder(null)} 
        />
      )}
      {selectedGroup && (
        <GroupDetailModal 
          group={selectedGroup} 
          onClose={() => setSelectedGroup(null)} 
        />
      )}
    </div>
  );
};

// ==================== المكون الرئيسي ====================
export default function Profileemploye() {
  const [showWorkerCV, setShowWorkerCV] = useState(false);
  const [showManagerCV, setShowManagerCV] = useState(false);
  const [showAddComment, setShowAddComment] = useState(false);
  const [showCommentsList, setShowCommentsList] = useState(false);
  const [workerStatus, setWorkerStatus] = useState("working");
  const [currentWorkPlace, setCurrentWorkPlace] = useState("Le Café Paris");
  
  // ========== حالة الطلبات (تأتي من الـ Backend) ==========
  const [orders, setOrders] = useState([
    { id: 1, name: "قهوة عربية", price: 150, status: "pending", time: "14:30", notes: "سكر أقل" },
    { id: 2, name: "شاي بالنعناع", price: 120, status: "pending", time: "14:32", notes: "" },
    { id: 3, name: "قهوة عربية", price: 150, status: "pending", time: "14:35", notes: "بدون سكر" },
    { id: 4, name: "كابتشينو", price: 250, status: "pending", time: "14:38", notes: "حليب ساخن" },
    { id: 5, name: "قهوة عربية", price: 150, status: "pending", time: "14:40", notes: "" },
    { id: 6, name: "شاي بالنعناع", price: 120, status: "pending", time: "14:42", notes: "نعناع طازج" },
  ]);
  
  const [comments, setComments] = useState([
    { id: 1, author: "Sophie Martin", text: "Excellente prestation ! Je recommande vivement 👍", rating: 5, date: "2024-03-15" },
    { id: 2, author: "Thomas Dubois", text: "Service rapide et professionnel. Très satisfait.", rating: 4, date: "2024-03-10" },
    { id: 3, author: "Marie Lambert", text: "Super expérience, à refaire ! 🌟", rating: 5, date: "2024-03-05" }
  ]);
  
  const [newComment, setNewComment] = useState({ author: "", text: "", rating: 5 });
  
  const [workerInfo, setWorkerInfo] = useState({
    name: "Jenna Stones",
    role: "Serveuse / Barmaid",
    experience: "5 ans d'expérience",
    skills: ["Service client", "Gestion des commandes", "Polyvalence", "Travail d'équipe", "Anglais courant", "Rapidité"],
    bio: "Serveuse professionnelle avec 5 ans d'expérience dans la restauration. Spécialisée dans le service rapide et la satisfaction client. Passionnée par mon métier et toujours souriante.",
    email: "jenna.stones@example.com",
    phone: "+33 6 12 34 56 78",
    location: "Paris, France",
    languages: ["Français", "Anglais", "Espagnol"]
  });
  
  const [workHistory, setWorkHistory] = useState([
    { place: "Le Café Paris", role: "Serveuse", duration: "2023 - Présent", rating: 5, review: "Excellente serveuse, très professionnelle !" },
    { place: "Restaurant La Mer", role: "Barmaid", duration: "2021 - 2023", rating: 4, review: "Bon travail, équipe sympathique." },
    { place: "Café Central", role: "Stagiaire Serveuse", duration: "2020 - 2021", rating: 4.5, review: "Apprentissage rapide, très motivée." }
  ]);
  
  const [currentRating, setCurrentRating] = useState(0);
  const [managerComment, setManagerComment] = useState("");
  
  // محاكاة وصول طلبات جديدة من الـ Backend
  useEffect(() => {
    const interval = setInterval(() => {
      // محاكاة طلب جديد كل 20 ثانية
      const newOrder = {
        id: Date.now(),
        name: ["قهوة عربية", "شاي بالنعناع", "كابتشينو", "لاتيه", "عصير برتقال", "كرواسون"][Math.floor(Math.random() * 6)],
        price: [150, 120, 250, 220, 180, 100][Math.floor(Math.random() * 6)],
        status: "pending",
        time: new Date().toLocaleTimeString('fr-FR', { hour: '2-digit', minute: '2-digit' }),
        notes: Math.random() > 0.7 ? "ملاحظة خاصة" : ""
      };
      
      setOrders(prev => [...prev, newOrder]);
    }, 20000); // كل 20 ثانية
    
    return () => clearInterval(interval);
  }, []);
  
  // تحديث حالة الطلبية
  const updateOrderStatus = (orderId, newStatus) => {
    setOrders(prev => prev.map(order => 
      order.id === orderId ? { ...order, status: newStatus } : order
    ));
    
    // إشعار للمستخدم
    const order = orders.find(o => o.id === orderId);
    if (order) {
      const statusText = newStatus === 'completed' ? 'تم التوصيل ✅' : 'تم الإلغاء ❌';
      alert(`📋 الطلب: ${order.name}\n📌 الحالة: ${statusText}`);
    }
  };
  
  const addComment = () => {
    if (newComment.author && newComment.text) {
      const comment = {
        id: comments.length + 1,
        author: newComment.author,
        text: newComment.text,
        rating: newComment.rating,
        date: new Date().toLocaleDateString('fr-FR')
      };
      setComments([comment, ...comments]);
      setNewComment({ author: "", text: "", rating: 5 });
      setShowAddComment(false);
      alert("✅ Merci pour votre commentaire !");
    } else {
      alert("⚠️ Veuillez entrer votre nom et votre commentaire");
    }
  };
  
  const addManagerReview = () => {
    if (currentRating > 0 && managerComment) {
      const newHistory = {
        place: currentWorkPlace,
        role: workerInfo.role,
        duration: new Date().toLocaleDateString('fr-FR'),
        rating: currentRating,
        review: managerComment
      };
      setWorkHistory([newHistory, ...workHistory]);
      setCurrentRating(0);
      setManagerComment("");
      alert("✅ Évaluation ajoutée avec succès !");
    } else {
      alert("⚠️ Veuillez sélectionner une note et ajouter un commentaire");
    }
  };
  
  const changeWorkPlace = (place) => {
    setCurrentWorkPlace(place.name);
    setSelectedPlace(null);
    setShowPlaceSelector(false);
    setWorkerStatus("working");
    alert(`✅ Lieu de travail changé : ${place.name}`);
  };
  
  const [selectedPlace, setSelectedPlace] = useState(null);
  const [showPlaceSelector, setShowPlaceSelector] = useState(false);
  
  const deactivateWorker = () => {
    setWorkerStatus("free");
    setCurrentWorkPlace("");
    alert("⚠️ Statut changé : En recherche d'emploi");
  };
  
  const activateWorker = () => {
    setShowPlaceSelector(true);
  };
  
  const availablePlaces = [
    { id: 1, name: "Le Café Paris", location: "Paris", type: "Café", icon: "☕" },
    { id: 2, name: "Restaurant La Mer", location: "Marseille", type: "Restaurant", icon: "🍽️" },
    { id: 3, name: "Tech Hub Lyon", location: "Lyon", type: "Bureau", icon: "💻" },
    { id: 4, name: "Startup Factory", location: "Toulouse", type: "Coworking", icon: "🚀" }
  ];

  // ==================== ستايل CSS ====================
  const style = `
    @keyframes gradientShift {
      0% { background-position: 0% 50%; }
      50% { background-position: 100% 50%; }
      100% { background-position: 0% 50%; }
    }
    
    @keyframes slideUp {
      from {
        opacity: 0;
        transform: translateY(30px);
      }
      to {
        opacity: 1;
        transform: translateY(0);
      }
    }
    
    @keyframes twinkle {
      0%, 100% { opacity: 0.2; transform: scale(1); }
      50% { opacity: 1; transform: scale(1.2); }
    }
    
    @keyframes gradient-border {
      0% { background-position: 0% 0%; }
      50% { background-position: 400% 0%; }
      100% { background-position: 0% 0%; }
    }
    
    @keyframes borderPulse {
      0%, 100% { opacity: 0.6; filter: blur(8px); }
      50% { opacity: 1; filter: blur(12px); }
    }
    
    .profile-hero-section {
      position: relative;
      background: linear-gradient(135deg, #0a0a2a, #1a1a3a, #0d0d2b, #0f0c29, #1a1a4a);
      background-size: 400% 400%;
      animation: gradientShift 12s ease infinite;
      min-height: 100vh;
      padding-top: 80px;
    }
    
    /* ===== ستايل قائمة الطلبات ===== */
    .order-list-container {
      position: fixed;
      bottom: 20px;
      right: 20px;
      width: 380px;
      max-width: calc(100% - 40px);
      background: rgba(0, 0, 0, 0.85);
      backdrop-filter: blur(20px);
      border-radius: 20px;
      border: 1px solid rgba(34, 197, 94, 0.3);
      box-shadow: 0 10px 40px rgba(0, 0, 0, 0.5), 0 0 20px rgba(34, 197, 94, 0.2);
      z-index: 100;
      transition: all 0.3s ease;
    }
    
    .order-list-header {
      display: flex;
      justify-content: space-between;
      align-items: center;
      padding: 15px 20px;
      background: linear-gradient(135deg, rgba(34, 197, 94, 0.2), rgba(34, 197, 94, 0.05));
      border-radius: 20px 20px 0 0;
      border-bottom: 1px solid rgba(34, 197, 94, 0.3);
    }
    
    .order-list-title {
      color: white;
      font-size: 1.1rem;
      font-weight: bold;
      margin: 0;
      display: flex;
      align-items: center;
      gap: 8px;
    }
    
    .order-count-badge {
      background: #22c55e;
      color: white;
      border-radius: 20px;
      padding: 2px 8px;
      font-size: 0.75rem;
      font-weight: bold;
    }
    
    .refresh-btn {
      background: rgba(255, 255, 255, 0.1);
      border: none;
      color: white;
      cursor: pointer;
      padding: 5px 8px;
      border-radius: 8px;
      font-size: 1rem;
      transition: all 0.2s;
    }
    
    .refresh-btn:hover {
      background: rgba(34, 197, 94, 0.3);
      transform: rotate(90deg);
    }
    
    .order-list-scroll {
      max-height: 450px;
      overflow-y: auto;
      padding: 10px;
    }
    
    .order-list-scroll::-webkit-scrollbar {
      width: 5px;
    }
    
    .order-list-scroll::-webkit-scrollbar-track {
      background: rgba(255, 255, 255, 0.1);
      border-radius: 10px;
    }
    
    .order-list-scroll::-webkit-scrollbar-thumb {
      background: #22c55e;
      border-radius: 10px;
    }
    
    .order-item {
      background: rgba(255, 255, 255, 0.1);
      border-radius: 12px;
      margin-bottom: 10px;
      cursor: pointer;
      transition: all 0.2s;
      border-left: 3px solid #22c55e;
      animation: slideUp 0.3s ease-out forwards;
      opacity: 0;
    }
    
    .order-item:hover {
      background: rgba(255, 255, 255, 0.15);
      transform: translateX(-3px);
    }
    
    .order-item.cancelled {
      border-left-color: #ef4444;
      opacity: 0.7;
    }
    
    .order-item.completed {
      border-left-color: #3b82f6;
      opacity: 0.7;
    }
    
    .order-item-content {
      padding: 12px 15px;
      display: flex;
      justify-content: space-between;
      align-items: center;
    }
    
    .order-info {
      display: flex;
      align-items: center;
      gap: 12px;
      flex: 1;
    }
    
    .order-icon {
      font-size: 1.8rem;
    }
    
    .order-details {
      flex: 1;
    }
    
    .order-name {
      color: white;
      font-weight: 600;
      font-size: 0.95rem;
    }
    
    .order-meta {
      display: flex;
      gap: 10px;
      margin-top: 4px;
    }
    
    .order-price {
      color: #22c55e;
      font-size: 0.8rem;
      font-weight: bold;
    }
    
    .order-quantity-badge {
      background: rgba(34, 197, 94, 0.2);
      color: #22c55e;
      padding: 0px 6px;
      border-radius: 10px;
      font-size: 0.7rem;
      font-weight: bold;
    }
    
    .order-actions {
      display: flex;
      align-items: center;
      gap: 10px;
    }
    
    .group-badge {
      background: rgba(34, 197, 94, 0.3);
      color: #22c55e;
      padding: 2px 8px;
      border-radius: 12px;
      font-size: 0.7rem;
      font-weight: bold;
    }
    
    .order-status {
      font-size: 1.2rem;
    }
    
    .order-status.completed {
      filter: drop-shadow(0 0 3px #3b82f6);
    }
    
    .order-status.cancelled {
      filter: drop-shadow(0 0 3px #ef4444);
    }
    
    .empty-orders {
      text-align: center;
      padding: 40px 20px;
      color: rgba(255, 255, 255, 0.5);
    }
    
    .empty-icon {
      font-size: 3rem;
      margin-bottom: 10px;
      opacity: 0.5;
    }
    
    .empty-sub {
      font-size: 0.75rem;
      margin-top: 5px;
    }
    
    .scroll-to-top {
      position: absolute;
      bottom: 10px;
      right: 10px;
      background: #22c55e;
      border: none;
      color: white;
      width: 35px;
      height: 35px;
      border-radius: 50%;
      cursor: pointer;
      font-size: 1.2rem;
      transition: all 0.2s;
      box-shadow: 0 2px 10px rgba(34, 197, 94, 0.4);
    }
    
    .scroll-to-top:hover {
      transform: scale(1.1);
      background: #15803d;
    }
    
    /* مودال الطلبات */
    .modal-overlay {
      position: fixed;
      top: 0;
      left: 0;
      right: 0;
      bottom: 0;
      background: rgba(0, 0, 0, 0.85);
      backdrop-filter: blur(10px);
      z-index: 1000;
      display: flex;
      align-items: center;
      justify-content: center;
      animation: fadeIn 0.3s ease;
    }
    
    .modal-content-order {
      background: linear-gradient(135deg, #1a1a3a, #0d0d2b);
      border-radius: 30px;
      padding: 30px;
      max-width: 400px;
      width: 90%;
      border: 2px solid #22c55e;
      box-shadow: 0 0 40px rgba(34, 197, 94, 0.3);
      animation: slideUp 0.4s ease;
    }
    
    .close-btn {
      float: right;
      background: none;
      border: none;
      color: white;
      font-size: 24px;
      cursor: pointer;
    }
    
    .order-detail-info {
      text-align: left;
      margin: 20px 0;
      background: rgba(255, 255, 255, 0.05);
      padding: 15px;
      border-radius: 15px;
    }
    
    .order-detail-info p {
      margin: 8px 0;
      color: rgba(255, 255, 255, 0.8);
    }
    
    .detail-label {
      font-weight: bold;
      color: #22c55e;
      display: inline-block;
      width: 90px;
    }
    
    .order-detail-buttons {
      display: flex;
      gap: 15px;
      justify-content: center;
      margin-top: 20px;
    }
    
    .btn-livre {
      background: linear-gradient(135deg, #22c55e, #15803d);
      border: none;
      padding: 10px 20px;
      border-radius: 25px;
      color: white;
      font-weight: bold;
      cursor: pointer;
      transition: all 0.2s;
    }
    
    .btn-annule {
      background: linear-gradient(135deg, #ef4444, #b91c1c);
      border: none;
      padding: 10px 20px;
      border-radius: 25px;
      color: white;
      font-weight: bold;
      cursor: pointer;
      transition: all 0.2s;
    }
    
    .btn-livre:hover, .btn-annule:hover {
      transform: scale(1.02);
    }
    
    .status-badge-detail {
      display: inline-block;
      padding: 2px 10px;
      border-radius: 15px;
      font-size: 0.75rem;
      margin-left: 8px;
    }
    
    .status-badge-detail.pending {
      background: #f59e0b;
      color: white;
    }
    
    .status-badge-detail.completed {
      background: #22c55e;
      color: white;
    }
    
    .status-badge-detail.cancelled {
      background: #ef4444;
      color: white;
    }
    
    @keyframes fadeIn {
      from { opacity: 0; }
      to { opacity: 1; }
    }
    
    @keyframes slideUp {
      from { transform: translateY(50px); opacity: 0; }
      to { transform: translateY(0); opacity: 1; }
    }
    
    .animate-slide-up {
      animation: slideUp 0.3s ease-out forwards;
    }
    
    /* باقي الستايلات الموجودة سابقاً */
    .shooting-stars {
      position: absolute;
      top: 0;
      left: 0;
      width: 100%;
      height: 100%;
      pointer-events: none;
      z-index: 1;
      overflow: hidden;
    }
    
    .star {
      position: absolute;
      background: white;
      border-radius: 50%;
      opacity: 0.6;
      animation: twinkle 3s ease-in-out infinite;
    }
    
    .gradient-border-box {
      position: relative;
      width: 150px;
      height: 150px;
      display: flex;
      align-items: center;
      justify-content: center;
      border-radius: 50%;
      margin-top: -60px;
      margin-left: -20px;
    }
    
    .gradient-border-box::before {
      content: "";
      position: absolute;
      inset: -4px;
      z-index: -1;
      background: linear-gradient(45deg, #ff0000, #ff7300, #fffb00, #48ff00, #00ffd5, #002bff, #7a00ff, #ff00c8, #ff0000);
      background-size: 450%;
      border-radius: 50%;
      animation: gradient-border 20s linear infinite;
      filter: blur(5px);
    }
    
    .cards-container {
      display: flex;
      gap: 20px;
      justify-content: center;
      margin-top: 40px;
      flex-wrap: wrap;
      position: relative;
      padding-bottom: 30px;
    }
    
    .cv-card {
      flex: 1;
      min-width: 260px;
      backdrop-filter: blur(15px);
      border-radius: 30px;
      padding: 35px 25px;
      cursor: pointer;
      transition: all 0.4s;
      text-align: center;
      position: relative;
      overflow: hidden;
      z-index: 5;
    }
    
    .cv-card:nth-child(1) {
      background: linear-gradient(135deg, #FF6B6B 0%, #FF8E53 50%, #FF6B6B 100%);
      background-size: 200% 200%;
    }
    
    .cv-card:nth-child(2) {
      background: linear-gradient(135deg, #4ECDC4 0%, #556270 50%, #4ECDC4 100%);
      background-size: 200% 200%;
    }
    
    .cv-card:nth-child(3) {
      background: linear-gradient(135deg, #A8E6CF 0%, #3E92CC 50%, #A8E6CF 100%);
      background-size: 200% 200%;
    }
    
    .cv-card:hover {
      transform: translateY(-8px);
    }
    
    .btn-contact {
      background: linear-gradient(135deg, #22c55e, #15803d);
      border: none;
      padding: 10px 25px;
      border-radius: 30px;
      color: white;
      font-weight: bold;
      cursor: pointer;
    }
    
    .btn-comment {
      background: linear-gradient(135deg, #ff6b6b, #f5576c);
      border: none;
      padding: 10px 25px;
      border-radius: 30px;
      color: white;
      font-weight: bold;
      cursor: pointer;
    }
    
    .modal-content {
      background: linear-gradient(135deg, #1a1a3a, #0d0d2b);
      border-radius: 30px;
      padding: 30px;
      max-width: 550px;
      width: 90%;
      max-height: 85vh;
      overflow-y: auto;
      border: 2px solid #22c55e;
    }
    
    .rating-star {
      font-size: 30px;
      cursor: pointer;
      color: #4a4a4a;
      transition: all 0.2s;
    }
    
    .rating-star.active {
      color: #ffc107;
    }
    
    .work-history-item {
      background: rgba(255,255,255,0.08);
      border-radius: 15px;
      padding: 15px;
      margin-bottom: 15px;
      border-left: 4px solid #22c55e;
    }
    
    .status-badge {
      display: inline-block;
      padding: 5px 12px;
      border-radius: 20px;
      font-size: 12px;
      font-weight: bold;
      margin-left: 10px;
    }
    
    .status-working {
      background: #22c55e;
      color: white;
    }
    
    .status-free {
      background: #ef4444;
      color: white;
    }
    
    .skill-tag {
      display: inline-block;
      padding: 4px 10px;
      background: rgba(34,197,94,0.2);
      border-radius: 15px;
      font-size: 11px;
      margin: 2px;
      color: #4ade80;
    }
    
    .btn-primary {
      background: linear-gradient(135deg, #22c55e, #15803d);
      border: none;
      padding: 10px 20px;
      border-radius: 25px;
      color: white;
      font-weight: bold;
      cursor: pointer;
    }
    
    .btn-danger {
      background: linear-gradient(135deg, #ef4444, #b91c1c);
      border: none;
      padding: 8px 16px;
      border-radius: 20px;
      color: white;
      font-weight: bold;
      cursor: pointer;
    }
    
    .comment-card {
      background: rgba(255,255,255,0.08);
      border-radius: 15px;
      padding: 15px;
      margin-bottom: 15px;
    }
    
    .profile-glow {
      position: absolute;
      top: 50%;
      left: 50%;
      transform: translate(-50%, -50%);
      width: 170px;
      height: 170px;
      background: radial-gradient(circle, rgba(34,197,94,0.3) 0%, rgba(34,197,94,0) 70%);
      border-radius: 50%;
      z-index: -1;
      animation: borderPulse 2s ease-in-out infinite;
    }
    
    .bg-white-card {
      background: rgba(255, 255, 255, 0.12);
      backdrop-filter: blur(16px);
      border-radius: 28px;
      border: 1px solid rgba(255, 255, 255, 0.25);
    }
    
    @media (max-width: 768px) {
      .order-list-container {
        width: calc(100% - 20px);
        right: 10px;
        bottom: 10px;
      }
      
      .cards-container {
        flex-direction: column;
      }
      
      .gradient-border-box {
        width: 120px;
        height: 120px;
        margin-top: -50px;
        margin-left: 0;
      }
    }
  `;

  return (
    <>
      <style>{style}</style>
      
      <Navbar />
      
      <div className="profile-hero-section">
        <div className="shooting-stars">
          {[...Array(30)].map((_, i) => (
            <div key={i} className="star" style={{
              left: `${Math.random() * 100}%`,
              top: `${Math.random() * 100}%`,
              width: `${Math.random() * 3 + 1}px`,
              height: `${Math.random() * 3 + 1}px`,
              animationDelay: `${Math.random() * 5}s`,
            }} />
          ))}
        </div>
        
        <main style={{ position: 'relative', zIndex: 10 }}>
          <section className="relative block" style={{ height: "350px", position: 'relative' }}>
            <div className="hero-image" style={{ 
              backgroundImage: "url('https://png.pngtree.com/thumb_back/fw800/background/20240602/pngtree-bartender-cleaning-counter-in-a-nice-pub-image_15737949.jpg')",
              backgroundSize: 'cover',
              backgroundPosition: 'center 40%',
              position: 'absolute',
              top: 0,
              width: '100%',
              height: '100%'
            }}></div>
            <div className="hero-overlay" style={{ position: 'absolute', top: 0, left: 0, width: '100%', height: '100%', background: 'linear-gradient(180deg, rgba(0,0,0,0.2) 0%, rgba(0,0,0,0.05) 30%, rgba(0,0,0,0) 50%, rgba(26,26,58,0.6) 100%)' }}></div>
          </section>
          
          <section className="relative py-16 bg-transparent">
            <div className="container mx-auto px-4">
              <div className="relative flex flex-col min-w-0 break-words bg-white-card w-full mb-6 shadow-xl rounded-lg -mt-48">
                <div className="px-6">
                  <div className="flex flex-wrap justify-center">
                    <div className="w-full lg:w-3/12 px-4 lg:order-2 flex justify-center">
                      <div className="profile-image-wrapper">
                        <div className="profile-glow"></div>
                        <div className="gradient-border-box">
                          <img alt="Jenna Stones" 
                            src="https://randomuser.me/api/portraits/women/68.jpg"
                            className="content" style={{ width: '100%', height: '100%', objectFit: 'cover', borderRadius: '50%' }} />
                        </div>
                      </div>
                    </div>
                    <div className="w-full lg:w-4/12 px-4 lg:order-3 lg:text-right lg:self-center"></div>
                    <div className="w-full lg:w-4/12 px-4 lg:order-1"></div>
                  </div>
                  
                  <div className="text-center mt-12">
                    <h3 className="text-4xl font-semibold leading-normal mb-2 text-white">
                      {workerInfo.name}
                      <span className={`status-badge ${workerStatus === 'working' ? 'status-working' : 'status-free'}`}>
                        {workerStatus === 'working' ? '✅ En poste' : '📢 En recherche'}
                      </span>
                    </h3>
                    {workerStatus === 'working' && currentWorkPlace && (
                      <p className="text-md text-green-400 font-semibold mt-2">
                        📍 Travaille chez : {currentWorkPlace}
                      </p>
                    )}
                    <div className="text-sm leading-normal mt-2 mb-2 text-gray-400 font-bold uppercase">
                      <i className="fas fa-map-marker-alt mr-2"></i> {workerInfo.location}
                    </div>
                    <div className="mb-2 text-gray-300 mt-10">
                      <i className="fas fa-briefcase mr-2 text-green-400"></i>
                      {workerInfo.role}
                    </div>
                  </div>
                  
                  <div className="action-buttons" style={{ display: 'flex', justifyContent: 'center', gap: '15px', marginTop: '20px' }}>
                    <button className="btn-contact" onClick={() => alert("📧 Email: jenna@example.com\n📱 Téléphone: +33 6 12 34 56 78")}>
                      📧 Contacter
                    </button>
                    <button className="btn-comment" onClick={() => setShowCommentsList(true)}>
                      💬 Commenter
                    </button>
                  </div>
                  
                  <div className="cards-container">
                    <div className="cv-card" onClick={() => setShowWorkerCV(true)}>
                      <div className="text-6xl mb-4">📄</div>
                      <h3 className="text-xl font-bold text-white mb-2">Mon CV</h3>
                      <p className="text-white/90 text-sm">Découvrez mon parcours professionnel</p>
                    </div>
                    
                    <div className="cv-card" onClick={() => setShowManagerCV(true)}>
                      <div className="text-6xl mb-4">⭐</div>
                      <h3 className="text-xl font-bold text-white mb-2">Évaluations</h3>
                      <p className="text-white/90 text-sm">Historique et retours des managers</p>
                    </div>
                    
                    <div className="cv-card" onClick={() => alert("🌟 Nouvelle opportunité à venir !")}>
                      <div className="text-6xl mb-4">🚀</div>
                      <h3 className="text-xl font-bold text-white mb-2">Projets</h3>
                      <p className="text-white/90 text-sm">Mes réalisations récentes</p>
                    </div>
                  </div>
                  
                  <div className="mt-10 py-10 border-t border-white/20 text-center">
                    <div className="flex flex-wrap justify-center">
                      <div className="w-full lg:w-9/12 px-4">
                        <p className="mb-4 text-lg leading-relaxed text-gray-200 italic">
                          "{workerInfo.bio}"
                        </p>
                        <div className="flex justify-center gap-2 mt-4 flex-wrap">
                          {workerInfo.skills.map((skill, i) => (
                            <span key={i} className="skill-tag">{skill}</span>
                          ))}
                        </div>
                      </div>
                    </div>
                  </div>
                </div>
              </div>
            </div>
          </section>
        </main>
      </div>
      
      {/* قائمة الطلبات */}
      <OrderList orders={orders} onUpdateOrderStatus={updateOrderStatus} />
      
      {/* باقي المودالات كما هي */}
      {showCommentsList && (
        <div className="modal-overlay" onClick={() => setShowCommentsList(false)}>
          <div className="modal-content" onClick={(e) => e.stopPropagation()}>
            <button onClick={() => setShowCommentsList(false)} className="close-btn">✕</button>
            <div className="text-center">
              <div className="text-6xl mb-4">💬</div>
              <h2 className="text-2xl font-bold text-white mb-2">Commentaires</h2>
              <button onClick={() => setShowAddComment(true)} className="btn-primary w-full mb-6">
                ✏️ Écrire un commentaire
              </button>
              <div className="mt-4">
                <h3 className="text-lg font-semibold text-white mb-3 text-left">
                  📖 Commentaires récents ({comments.length})
                </h3>
                {comments.map((comment) => (
                  <div key={comment.id} className="comment-card">
                    <div className="flex justify-between items-start flex-wrap mb-2">
                      <div>
                        <h4 className="text-white font-bold">{comment.author}</h4>
                        <p className="text-gray-400 text-xs">{comment.date}</p>
                      </div>
                      <div className="stars">
                        {[...Array(5)].map((_, i) => (
                          <span key={i} style={{ color: i < comment.rating ? '#ffc107' : '#4a4a4a', fontSize: '16px' }}>★</span>
                        ))}
                      </div>
                    </div>
                    <p className="text-gray-300 text-sm mt-2">{comment.text}</p>
                  </div>
                ))}
              </div>
            </div>
          </div>
        </div>
      )}
      
      {showAddComment && (
        <div className="modal-overlay" onClick={() => setShowAddComment(false)}>
          <div className="modal-content" onClick={(e) => e.stopPropagation()}>
            <button onClick={() => setShowAddComment(false)} className="close-btn">✕</button>
            <div>
              <div className="text-center">
                <div className="text-6xl mb-4">✏️</div>
                <h2 className="text-2xl font-bold text-white mb-2">Nouveau commentaire</h2>
              </div>
              <div className="mt-4">
                <label className="text-white text-sm block mb-2">👤 Votre nom</label>
                <input type="text" className="w-full p-3 rounded-xl bg-white/10 text-white border border-green-500/30"
                  value={newComment.author} onChange={(e) => setNewComment({...newComment, author: e.target.value})}
                  placeholder="Entrez votre nom" />
              </div>
              <div className="mt-3">
                <label className="text-white text-sm block mb-2">⭐ Note (1-5)</label>
                <div className="rating-input" style={{ display: 'flex', gap: '10px', justifyContent: 'center' }}>
                  {[1,2,3,4,5].map(star => (
                    <span key={star} className={`rating-star ${newComment.rating >= star ? 'active' : ''}`}
                      onClick={() => setNewComment({...newComment, rating: star})}>★</span>
                  ))}
                </div>
              </div>
              <div className="mt-3">
                <label className="text-white text-sm block mb-2">💬 Votre commentaire</label>
                <textarea className="w-full p-3 rounded-xl bg-white/10 text-white border border-green-500/30" rows="4"
                  value={newComment.text} onChange={(e) => setNewComment({...newComment, text: e.target.value})}
                  placeholder="Écrivez votre commentaire ici..."></textarea>
              </div>
              <button onClick={addComment} className="btn-primary w-full mt-4">
                📤 Publier le commentaire
              </button>
            </div>
          </div>
        </div>
      )}
      
      {showWorkerCV && (
        <div className="modal-overlay" onClick={() => setShowWorkerCV(false)}>
          <div className="modal-content" onClick={(e) => e.stopPropagation()}>
            <button onClick={() => setShowWorkerCV(false)} className="close-btn">✕</button>
            <div style={{ textAlign: 'center' }}>
              <div className="text-6xl mb-4">👩‍💻</div>
              <h2 className="text-2xl font-bold text-white mb-2">{workerInfo.name}</h2>
              <p className="text-green-400 mb-4">{workerInfo.role}</p>
              <div className="text-left">
                <h3 className="text-xl font-bold text-white mt-4 mb-2">📋 Profil</h3>
                <p className="text-gray-300">{workerInfo.bio}</p>
                <h3 className="text-xl font-bold text-white mt-4 mb-2">💪 Compétences</h3>
                <div className="flex flex-wrap gap-2">
                  {workerInfo.skills.map((skill, i) => (
                    <span key={i} className="skill-tag">{skill}</span>
                  ))}
                </div>
                <h3 className="text-xl font-bold text-white mt-4 mb-2">📞 Contact</h3>
                <p className="text-gray-300">📧 {workerInfo.email}</p>
                <p className="text-gray-300">📱 {workerInfo.phone}</p>
              </div>
            </div>
          </div>
        </div>
      )}
      
      {showManagerCV && (
        <div className="modal-overlay" onClick={() => setShowManagerCV(false)}>
          <div className="modal-content" onClick={(e) => e.stopPropagation()} style={{ maxWidth: '700px' }}>
            <button onClick={() => setShowManagerCV(false)} className="close-btn">✕</button>
            <div>
              <div className="text-center">
                <div className="text-6xl mb-4">⭐</div>
                <h2 className="text-2xl font-bold text-white mb-2">Gestion des évaluations</h2>
              </div>
              
              <div style={{ background: 'rgba(34,197,94,0.1)', borderRadius: '20px', padding: '20px', marginBottom: '20px' }}>
                <h3 className="text-lg font-bold text-green-400 mb-3">👨‍💼 Panel Manager</h3>
                <div className="flex gap-3 flex-wrap mb-4">
                  {workerStatus !== 'working' && (
                    <button onClick={() => setShowPlaceSelector(true)} className="btn-primary">✅ Activer</button>
                  )}
                  {workerStatus === 'working' && (
                    <button onClick={deactivateWorker} className="btn-danger">🚫 Terminer</button>
                  )}
                </div>
                
                {showPlaceSelector && (
                  <div className="place-selector" style={{ display: 'grid', gridTemplateColumns: 'repeat(auto-fit, minmax(180px, 1fr))', gap: '10px', marginTop: '10px' }}>
                    {availablePlaces.map(place => (
                      <div key={place.id} onClick={() => changeWorkPlace(place)} style={{ background: 'rgba(34,197,94,0.15)', padding: '12px', borderRadius: '12px', cursor: 'pointer', textAlign: 'center' }}>
                        <div className="text-2xl">{place.icon}</div>
                        <div className="text-white font-bold text-sm">{place.name}</div>
                      </div>
                    ))}
                  </div>
                )}
                
                <div className="mt-3">
                  <label className="text-white text-sm">⭐ Note (1-5)</label>
                  <div className="rating-input" style={{ display: 'flex', gap: '10px', justifyContent: 'center', marginTop: '5px' }}>
                    {[1,2,3,4,5].map(star => (
                      <span key={star} className={`rating-star ${currentRating >= star ? 'active' : ''}`}
                        onClick={() => setCurrentRating(star)}>★</span>
                    ))}
                  </div>
                </div>
                <div className="mt-3">
                  <label className="text-white text-sm">💬 Commentaire</label>
                  <textarea className="w-full p-2 rounded-lg mt-1 bg-white/10 text-white" rows="3"
                    value={managerComment} onChange={(e) => setManagerComment(e.target.value)}
                    placeholder="Écrivez votre commentaire..."></textarea>
                </div>
                <button onClick={addManagerReview} className="btn-primary w-full mt-3">
                  ✅ Ajouter
                </button>
              </div>
              
              <h3 className="text-lg font-bold text-white mb-3">📋 Historique</h3>
              {workHistory.map((work, index) => (
                <div key={index} className="work-history-item">
                  <div className="flex justify-between items-center flex-wrap">
                    <h4 className="text-white font-bold">{work.place}</h4>
                    <div className="stars">
                      {[...Array(5)].map((_, i) => (
                        <span key={i} style={{ color: i < work.rating ? '#ffc107' : '#4a4a4a', fontSize: '16px' }}>★</span>
                      ))}
                    </div>
                  </div>
                  <p className="text-gray-300 text-sm">{work.role} • {work.duration}</p>
                  <p className="text-gray-400 text-sm mt-2">"{work.review}"</p>
                </div>
              ))}
            </div>
          </div>
        </div>
      )}
      
      <Footer />
    </>
  );
}
